// ─── TYPED INPUT WITH AUTOCOMPLETE ───────────────────────────────────────────
function TypedInput({ question, diff, hintsEnabled, onAnswer }) {
  const [val, setVal] = useState("");
  const [suggestions, setSuggestions] = useState([]);
  const [state, setState] = useState(null);
  const [showHint, setShowHint] = useState(false);

  // Derive the hint: first letter of the correct answer
  const correctAnswer = question.o ? question.o[question.a] : "";
  const firstLetter = correctAnswer ? correctAnswer[0].toUpperCase() : "";

  useEffect(() => {
    if (val.length >= 2 && !state) setSuggestions(getACSuggestions(val));
    else setSuggestions([]);
  }, [val, state]);

  const submit = useCallback((v) => {
    const answer = (v || val).trim();
    if (!answer || state) return;
    setSuggestions([]);
    const correct = checkTyped(answer, question);
    setState(correct ? "correct" : "wrong");
    setVal(v || val);
    onAnswer(correct);
  }, [val, state, question, onAnswer]);

  const pick = (s) => { setVal(s); setSuggestions([]); setTimeout(() => submit(s), 60); };

  const highlight = (s) => {
    const v = norm(val);
    const sn = norm(s);
    const i = sn.indexOf(v);
    if (i === -1) return s;
    return <>{s.slice(0, i)}<span className="ac-hi">{s.slice(i, i + v.length)}</span>{s.slice(i + v.length)}</>;
  };

  return (
    <div>
      <div className="typed-outer">
        <input
          className={`typed-inp${state ? ` ${state}` : ""}`}
          placeholder="Type your answer…"
          value={val}
          onChange={e => setVal(e.target.value)}
          onKeyDown={e => e.key === "Enter" && submit()}
          disabled={!!state}
          autoFocus
        />
        {suggestions.length > 0 && (
          <div className="ac-list">
            {suggestions.map((s, i) => (
              <div key={i} className="ac-row" onMouseDown={() => pick(s)}>{highlight(s)}</div>
            ))}
          </div>
        )}
      </div>
      {hintsEnabled !== false && diff === "easy" && !state && val.length === 0 && firstLetter && (
        <div className="hint-note">💡 Starts with "{firstLetter}"</div>
      )}
      <button className="typed-btn" onClick={() => submit()} disabled={!val.trim() || !!state}>Submit →</button>
    </div>
  );
}

// ─── SOUND EFFECTS ────────────────────────────────────────────────────────────
function createSound(type) {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    if (type === "correct") {
      osc.frequency.setValueAtTime(523, ctx.currentTime);       // C5
      osc.frequency.setValueAtTime(659, ctx.currentTime + 0.1); // E5
      gain.gain.setValueAtTime(0.15, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
      osc.start(); osc.stop(ctx.currentTime + 0.3);
    } else if (type === "wrong") {
      osc.type = "sawtooth";
      osc.frequency.setValueAtTime(200, ctx.currentTime);
      osc.frequency.setValueAtTime(150, ctx.currentTime + 0.1);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
      osc.start(); osc.stop(ctx.currentTime + 0.25);
    } else if (type === "levelup") {
      [523,659,784,1047].forEach((freq, i) => {
        const o2 = ctx.createOscillator();
        const g2 = ctx.createGain();
        o2.connect(g2); g2.connect(ctx.destination);
        o2.frequency.value = freq;
        g2.gain.setValueAtTime(0.12, ctx.currentTime + i*0.1);
        g2.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i*0.1 + 0.2);
        o2.start(ctx.currentTime + i*0.1);
        o2.stop(ctx.currentTime + i*0.1 + 0.2);
      });
    }
  } catch {}
}

function haptic(type) {
  try {
    if (!navigator.vibrate) return;
    if (type === "correct") navigator.vibrate(40);
    else if (type === "hardCorrect") navigator.vibrate([30, 40, 30, 40, 60]);  // Triumphant triple-buzz for hard questions
    else if (type === "wrong") navigator.vibrate([30, 20, 60]);
    else if (type === "levelup") navigator.vibrate([50, 30, 50, 30, 100]);
    else if (type === "select") navigator.vibrate(15);
  } catch {}
}

// ─── HOT STREAK ENGINE ────────────────────────────────────────────────────────
function HotStreakEngine({ questions, onComplete, onBack }) {
  const [idx, setIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [flash, setFlash] = useState(null); // 'correct' | 'wrong'
  const [done, setDone] = useState(false);
  const timerRef = useRef(null);
  const q = questions[idx % questions.length];

  useEffect(() => {
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) { clearInterval(timerRef.current); setDone(true); return 0; }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  useEffect(() => {
    if (done) onComplete({ score, total: idx, bestStreak: score });
  }, [done]);

  const answer = (i) => {
    if (done || flash) return;
    const correct = i === q.a;
    if (correct) setScore(s => s + 1);
    setFlash(correct ? 'correct' : 'wrong');
    setTimeout(() => { setFlash(null); setIdx(i => i + 1); }, 400);
  };

  const pct = (timeLeft / 60) * 100;
  const barColor = timeLeft > 20 ? 'var(--accent)' : timeLeft > 10 ? 'var(--gold)' : 'var(--red)';

  return (
    <div className="quiz-wrap">
      <div className="q-top">
        <button className="back-btn" onClick={() => { clearInterval(timerRef.current); onBack(); }}>←</button>
        <div className="prog-wrap"><div className="prog-bar" style={{width:`${pct}%`, background:barColor, transition:'width 1s linear'}} /></div>
        <span className="q-ctr" style={{color: timeLeft <= 10 ? 'var(--red)' : 'var(--t2)', fontWeight: timeLeft <= 10 ? 800 : 500}}>{timeLeft}s</span>
      </div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <div style={{fontSize:12,color:'var(--t2)',fontFamily:"'JetBrains Mono',monospace",letterSpacing:1}}>⚡🔥 HOT STREAK</div>
        <div style={{fontSize:22,fontWeight:800,color:'var(--accent)'}}>{score} <span style={{fontSize:13,color:'var(--t3)',fontWeight:500}}>pts</span></div>
      </div>
      <div className={`q-card${flash ? ` q-card-${flash}` : ''}`} style={{transition:'background 0.2s'}}>
        <div className="q-tag">{CAT_LABELS[q.cat] || q.cat}</div>
        <div className="q-text">{q.q}</div>
      </div>
      <div className="opts">
        {q.o.map((opt, i) => (
          <button key={i} className="opt" onClick={() => answer(i)} disabled={!!flash}>
            <span className="opt-l">{['A','B','C','D'][i]}</span>{opt}
          </button>
        ))}
      </div>
    </div>
  );
}

// ─── TRUE OR FALSE ENGINE ─────────────────────────────────────────────────────
function TrueFalseEngine({ questions, onComplete, onBack }) {
  const [idx, setIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [flash, setFlash] = useState(null);
  const [done, setDone] = useState(false);
  const total = questions?.length || 0;
  const timeoutRef = useRef(null);
  const onCompleteRef = useRef(onComplete);
  useEffect(() => { onCompleteRef.current = onComplete; }, [onComplete]);

  // Cleanup any pending timeout on unmount
  useEffect(() => () => { if (timeoutRef.current) clearTimeout(timeoutRef.current); }, []);

  useEffect(() => {
    if (done) onCompleteRef.current({ score, total, bestStreak: score });
  }, [done, score, total]);

  const answer = (val) => {
    if (flash) return;
    if (!questions || !questions[idx]) return;
    // Bulletproof: handle both a:true/false (boolean) and a:1/0 (number) formats
    const qa = questions[idx]?.a;
    const qAsBool = qa === true || qa === 1;
    const correct = val === qAsBool;
    if (correct) setScore(s => s + 1);
    setFlash(correct ? 'correct' : 'wrong');
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    timeoutRef.current = setTimeout(() => {
      setFlash(null);
      if (idx + 1 >= total) setDone(true);
      else setIdx(i => i + 1);
    }, 700);
  };

  // Safety: if questions missing or done, render nothing (onComplete will have fired)
  if (done || !questions || questions.length === 0) return null;
  const q = questions[idx];
  if (!q) return null;

  return (
    <div className="quiz-wrap">
      <div className="q-top">
        <button className="back-btn" onClick={onBack}>←</button>
        <div className="prog-wrap"><div className="prog-bar" style={{width:`${((idx + (flash?1:0)) / total) * 100}%`}} /></div>
        <span className="q-ctr">{idx + 1}/{total}</span>
      </div>
      <div style={{textAlign:'center',padding:'8px 0 4px'}}>
        <span style={{fontSize:10,fontFamily:"'JetBrains Mono',monospace",color:'var(--accent)',letterSpacing:2,textTransform:'uppercase'}}>✅ TRUE OR FALSE</span>
      </div>
      <div className={`q-card${flash ? ` q-card-${flash}` : ''}`} style={{minHeight:140,display:'flex',alignItems:'center',justifyContent:'center',textAlign:'center',transition:'background 0.3s'}}>
        <div className="q-text" style={{fontSize:'var(--q-font-size, 18px)',lineHeight:1.5}}>{q?.s || q?.q}</div>
      </div>
      {flash && (
        <div className={`feedback ${flash}`} style={{textAlign:'center',fontSize:20,fontWeight:800}}>
          {flash === 'correct' ? '✓ Correct!' : `✗ ${(q.a === true || q.a === 1) ? 'TRUE' : 'FALSE'}`}
        </div>
      )}
      {!flash && (
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginTop:16}}>
          <button className="btn" onClick={() => answer(true)}
            style={{padding:'22px',fontSize:18,fontWeight:800,borderRadius:16,background:'rgba(74,222,128,0.12)',border:'2px solid var(--accent)',color:'var(--accent)'}}>
            ✓ TRUE
          </button>
          <button className="btn" onClick={() => answer(false)}
            style={{padding:'22px',fontSize:18,fontWeight:800,borderRadius:16,background:'rgba(248,113,113,0.12)',border:'2px solid var(--red)',color:'var(--red)'}}>
            ✗ FALSE
          </button>
        </div>
      )}
    </div>
  );
}

// ─── QUIZ ENGINE ──────────────────────────────────────────────────────────────
function QuizEngine({ questions, mode, diff, timerEnabled, soundEnabled, hintsEnabled, playerName, roomCode, isHost, onComplete, onBack, survivalBest }) {
  const [idx, setIdx] = useState(0);
  const [selected, setSelected] = useState(null);   // MCQ selected index
  const [typedResult, setTypedResult] = useState(null); // 'correct' | 'wrong' | null
  const isSpeed = mode === "speed";
  const timerDuration = isSpeed ? 8 : 20;
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [bestStreak, setBestStreak] = useState(0);
  const [timeLeft, setTimeLeft] = useState(timerDuration);
  const [speedScore, setSpeedScore] = useState(0);
  const [opponentScore, setOpponentScore] = useState(null);
  const [done, setDone] = useState(false);
  const timerRef = useRef(null);
  const pollRef = useRef(null);
  const onCompleteRef = useRef(onComplete);
  useEffect(() => { onCompleteRef.current = onComplete; }, [onComplete]);
  const [showQuit, setShowQuit] = useState(false);
  const [showNext, setShowNext] = useState(false);
  const advanceRef = useRef(null);
  const [wrongAnswers, setWrongAnswers] = useState([]);
  const [hardRightBurst, setHardRightBurst] = useState(false);

  const total = questions?.length || 0;
  const q = questions?.[idx];
  const timed = (timerEnabled !== false) && mode !== "survival" && mode !== "legends" && q?.type !== "tf";
  const isTyped = q?.type === "typed";
  const isTF = q?.type === "tf";
  const answered = selected !== null || typedResult !== null;

  const doAdvance = useCallback((ns, nb, correct) => {
    if (mode === "survival" && !correct) { setDone(true); onCompleteRef.current({ score: ns, total: idx + 1, bestStreak: nb, wrongAnswers }); return; }
    if (idx + 1 >= total) { setDone(true); onCompleteRef.current({ score: ns, total, bestStreak: nb, wrongAnswers, speedScore }); return; }
    setIdx(i => i + 1); setSelected(null); setTypedResult(null); setShowNext(false);
    if (timed) setTimeLeft(timerDuration);
  }, [idx, total, mode, timed]);

  const advance = useCallback((ns, nb, correct) => {
    if (mode === "survival" && !correct) { doAdvance(ns, nb, correct); return; }
    if (correct === "timeout") { setTimeout(() => doAdvance(ns, nb, false), 800); return; }
    setShowNext({ ns, nb, correct });
  }, [mode, doAdvance]);
  useEffect(() => { advanceRef.current = advance; }, [advance]);

  const registerAnswer = useCallback((correct) => {
    clearInterval(timerRef.current);
    const ns = correct ? score + 1 : score;
    const nst = correct ? streak + 1 : 0;
    const nb = Math.max(bestStreak, nst);
    setScore(ns); setStreak(nst); setBestStreak(nb);
    if (!correct && q && correct !== "timeout") {
      setWrongAnswers(prev => [...prev, { q: q.q, correct: q.type === "typed" ? q.typed_a : q.type === "tf" ? (q.a ? "TRUE" : "FALSE") : q.o[q.a], cat: q.cat }]);
    }
    if (isSpeed && correct === true) { setSpeedScore(prev => prev + 100 + timeLeft * 10); }
    if (isSpeed && correct) {
      const timeBonus = timeLeft * 10;
      setSpeedScore(prev => prev + 100 + timeBonus);
    }
    if (mode === "online" && roomCode && window.storage) {
      const key = isHost ? "hostScore" : "guestScore";
      window.storage?.get(`biq_room:${roomCode}`, true).then(res => {
        if (res) { const r = JSON.parse(res.value); r[key] = ns; window.storage?.set(`biq_room:${roomCode}`, JSON.stringify(r), true); }
      }).catch(() => {});
    }
    advance(ns, nb, correct);
  }, [score, streak, bestStreak, mode, roomCode, isHost, advance]);

  const handleMCQ = useCallback((i) => {
    if (answered || done) return;
    setSelected(i);
    // T/F questions store answer as boolean OR number; MCQ stores as index
    const qAsBool = q.a === true || q.a === 1;
    const correct = q.type === "tf" ? ((i === 1) === qAsBool) : (i === q.a);
    if (soundEnabled) createSound(correct ? "correct" : "wrong");
    // Bigger celebration for HARD questions right
    if (correct && q.diff === "hard") {
      haptic("hardCorrect");
      setHardRightBurst(true);
      setTimeout(() => setHardRightBurst(false), 1500);
    } else {
      haptic(correct ? "correct" : "wrong");
    }
    registerAnswer(correct);
  }, [answered, done, q, registerAnswer, soundEnabled]);

  useEffect(() => {
    if (!timed || done || isTyped) return;
    setTimeLeft(timerDuration);
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) {
          clearInterval(timerRef.current);
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    // Separate effect watches for timeout (avoids stale closure entirely)
    const timeoutMs = (timerDuration * 1000) + 100;
    const timeoutId = setTimeout(() => {
      setScore(s => {
        setStreak(0);
        setBestStreak(b => {
          setSelected(questions[idx]?.a ?? -1);
          advanceRef.current?.(s, b, "timeout");
          return b;
        });
        return s;
      });
    }, timeoutMs);
    return () => { clearInterval(timerRef.current); clearTimeout(timeoutId); };
  }, [idx, timed, done, isTyped]);

  useEffect(() => {
    if (mode !== "online" || !roomCode) return;
    pollRef.current = setInterval(async () => {
      try {
        const res = await window.storage?.get(`biq_room:${roomCode}`, true);
        if (res) { const r = JSON.parse(res.value); const os = isHost ? r.guestScore : r.hostScore; if (os != null) setOpponentScore(os); }
      } catch {}
    }, 2000);
    return () => clearInterval(pollRef.current);
  }, [mode, roomCode, isHost]);

  if (done) return null;
  if (!q) return (
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:"60vh",gap:16}}>
      <div style={{fontSize:32}}>⚽</div>
      <div style={{fontFamily:"'Inter',sans-serif",fontSize:14,color:"var(--t2)"}}>Loading questions…</div>
      <div style={{fontFamily:"'JetBrains Mono',monospace",fontSize:11,color:"var(--t3)"}}>mode:{mode} q:{questions.length}</div>
      <button onClick={onBack} style={{marginTop:8,padding:"10px 20px",background:"var(--s2)",border:"1px solid var(--border)",borderRadius:10,color:"var(--text)",fontFamily:"'Inter',sans-serif",fontSize:14,cursor:"pointer"}}>← Go Back</button>
    </div>
  );

  return (
    <div className={`quiz-wrap${q?.cat ? ` cat-${q.cat}` : ""}`}>
      {hardRightBurst && <HardRightBurst />}
      {hardRightBurst && (
        <div style={{
          position:"fixed",
          top:"28%",
          left:"50%",
          transform:"translate(-50%, -50%)",
          background:"linear-gradient(135deg, #FBBF24 0%, #F59E0B 100%)",
          color:"#1a1a1a",
          padding:"10px 22px",
          borderRadius:100,
          fontSize:13,
          fontWeight:900,
          letterSpacing:1.5,
          boxShadow:"0 8px 32px rgba(251, 191, 36, 0.5), 0 2px 8px rgba(0,0,0,0.3)",
          zIndex:501,
          pointerEvents:"none",
          fontFamily:"'JetBrains Mono', monospace",
          animation:"hardRightBadge 1.5s cubic-bezier(0.22, 1, 0.36, 1) forwards",
        }}>
          🏆 HARD · NAILED IT
        </div>
      )}
      <div className="q-top">
        <button className="back-btn" onClick={() => {
          if (idx === 0) { onBack(); return; }
          setShowQuit(true);
        }}>←</button>
        <div className="prog-wrap"><div className="prog-bar" style={{ width: `${((idx + (answered ? 1 : 0)) / total) * 100}%` }} /></div>
        <div className="q-top-right">
          {score > 0 && <span className="q-score-live">{score}<span className="q-score-tick"> ✓</span></span>}
          <span className="q-ctr">{idx + 1}/{total}</span>
        </div>
      </div>

      {mode === "online" && (
        <div className="vs-bar">
          <div className="pc me"><div className="pc-name">{playerName||"You"}</div><div className="pc-score">{score}</div></div>
          <div className="vs-lbl">VS</div>
          <div className="pc"><div className="pc-name">Opp.</div><div className="pc-score">{opponentScore??"—"}</div></div>
        </div>
      )}

      {mode === "survival" && (
        <div className="streak-bar">
          <div className="streak-n">🔥 {streak}</div>
          <div className="streak-info">
            <strong>{streak === 0 ? "Survival Mode" : streak === 1 ? "First one!" : streak < 5 ? "Keep going!" : streak < 10 ? "On fire! 🔥" : "Unstoppable!"}</strong>
            {survivalBest > 0 && <span style={{fontSize:11,color:"var(--t3)",marginLeft:6}}>PB: {survivalBest}</span>}
            {streak > 0 && survivalBest > 0 && streak >= survivalBest && <span style={{fontSize:11,color:"var(--gold)",marginLeft:4,fontWeight:700}}>🏆 New PB!</span>}
          </div>
        </div>
      )}

      {timed && !isTyped && (
        <div className="timer-row">
          <div className="timer-track">
            <div className="timer-fill" style={{
              width:`${(timeLeft/timerDuration)*100}%`,
              background: (timeLeft/timerDuration) > 0.5 ? "var(--accent)" : (timeLeft/timerDuration) > 0.25 ? "var(--gold)" : "var(--red)"
            }}/>
          </div>
          <span className={`timer${(timeLeft/timerDuration)<=0.25?" urgent":""}`}>{timeLeft}s</span>
        </div>
      )}

      <div className="q-card">
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
          <div className="q-tag" style={{marginBottom:0}}>{CAT_LABELS[q.cat]||q.cat}</div>
          <button onClick={(e) => {
            e.stopPropagation();
            try { haptic("select"); } catch {}
            // Fire-and-forget flag — no await, no crash risk
            try {
              const p = window.storage?.get("biq_flagged_qs");
              if (p && p.then) {
                p.then(existing => {
                  const flags = (existing && existing.value) ? JSON.parse(existing.value) : [];
                  flags.push({ q: q.q, cat: q.cat, diff: q.diff, time: Date.now() });
                  const p2 = window.storage?.set("biq_flagged_qs", JSON.stringify(flags.slice(-50)));
                  if (p2 && p2.catch) p2.catch(() => {});
                }).catch(() => {});
              }
            } catch {}
          }} style={{background:"none",border:"none",cursor:"pointer",fontSize:13,color:"var(--t3)",padding:"2px 4px",lineHeight:1}} title="Flag question">🚩</button>
        </div>
        <div className="q-text" style={{fontSize:"var(--q-font-size, 18px)"}}>{q.q}</div>
      </div>

      {isTF ? (
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:8}}>
          {[true, false].map(val => {
            const isAnswered = selected !== null;
            // T/F answers stored as either boolean (TF_STATEMENTS) or number (QB: a:1/0)
            const qAsBool = q.a === true || q.a === 1;
            const isCorrect = val === qAsBool;
            const isChosen = selected === (val ? 1 : 0);
            let bg = val ? "rgba(74,222,128,0.1)" : "rgba(248,113,113,0.1)";
            let border = val ? "2px solid var(--accent)" : "2px solid var(--red)";
            let color = val ? "var(--accent)" : "var(--red)";
            if (isAnswered) {
              if (isCorrect) { bg = "rgba(74,222,128,0.25)"; border = "2px solid var(--accent)"; }
              else if (isChosen) { bg = "rgba(248,113,113,0.25)"; border = "2px solid var(--red)"; }
              else { bg = "var(--s2)"; border = "2px solid transparent"; color = "var(--t3)"; }
            }
            return (
              <button key={String(val)} disabled={isAnswered}
                onClick={() => { haptic("select"); handleMCQ(val ? 1 : 0); }}
                onPointerDown={e => { if (!isAnswered) e.currentTarget.style.transform = "scale(0.97)"; }}
                onPointerUp={e => { e.currentTarget.style.transform = ""; }}
                style={{padding:"20px 8px",fontSize:17,fontWeight:800,borderRadius:16,
                  background:bg,border,color,cursor:isAnswered?"default":"pointer",transition:"all 0.15s"}}>
                {isAnswered && isCorrect ? "✓ " : isAnswered && isChosen && !isCorrect ? "✗ " : ""}{val ? "TRUE" : "FALSE"}
              </button>
            );
          })}
        </div>
      ) : !isTyped ? (
        <div className="opts">
          {q.o.map((opt, i) => {
            const answered = selected !== null;
            const isCorrect = i === q.a;
            const isChosen = i === selected;
            let cls = "opt";
            if (answered) {
              if (isCorrect) cls += " correct";
              else if (isChosen) cls += " wrong";
              else cls += " neutral-after";
            }
            const icon = answered && isCorrect ? "✓" : answered && isChosen ? "✗" : LETTERS[i];
            return (
              <button key={i} className={cls} onClick={() => handleMCQ(i)} disabled={answered}
                onPointerDown={e => { if (!answered) e.currentTarget.style.transform = "scale(0.97)"; }}
                onPointerUp={e => { e.currentTarget.style.transform = ""; }}
                onPointerLeave={e => { e.currentTarget.style.transform = ""; }}
              >
                <span className="opt-l">{icon}</span>{opt}
              </button>
            );
          })}
        </div>
      ) : (
        <TypedInput key={idx} question={q} diff={diff} hintsEnabled={hintsEnabled} onAnswer={(correct) => {
          setTypedResult(correct ? "correct" : "wrong");
          if (correct && q.diff === "hard") {
            haptic("hardCorrect");
            setHardRightBurst(true);
            setTimeout(() => setHardRightBurst(false), 1500);
          }
          registerAnswer(correct);
        }} />
      )}

      {answered && q?.hint && (
        <div style={{
          marginTop:10,
          padding:"10px 14px",
          background:"var(--s1)",
          border:"1px solid var(--border)",
          borderRadius:10,
          fontSize:13,
          lineHeight:1.5,
          color:"var(--t2)",
          animation:"fadeIn 0.4s ease-out"
        }}>
          <div style={{fontSize:10,fontWeight:700,color:"var(--t3)",letterSpacing:1.5,textTransform:"uppercase",fontFamily:"'JetBrains Mono',monospace",marginBottom:4}}>💡 Why?</div>
          <div>{q.hint}</div>
        </div>
      )}

      {answered && (
        <div className={`feedback ${(isTF ? ((selected === 1) === (q?.a === true || q?.a === 1)) : (selected === q?.a || typedResult === "correct")) ? "correct" : "wrong"}`}>
          <span style={{flex:1,minWidth:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{(isTF ? ((selected === 1) === (q?.a === true || q?.a === 1)) : (selected === q?.a || typedResult === "correct"))
            ? "✓ Correct!"
            : isTyped
              ? `✗ ${q.typed_a}`
              : isTF
              ? `✗ ${(q?.a === true || q?.a === 1) ? "TRUE" : "FALSE"}`
              : `✗ ${q.o[q.a]}`
          }</span>
          {showNext && (
            <button className="next-btn" onClick={() => doAdvance(showNext.ns, showNext.nb, showNext.correct)}>
              {idx + 1 >= total ? "Results →" : "Next →"}
            </button>
          )}
        </div>
      )}

      {showQuit && (
        <div className="modal-overlay" onClick={() => setShowQuit(false)}>
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <div className="modal-title">Quit this game?</div>
            <div className="modal-body">Your progress will be lost.</div>
            <div className="modal-btns">
              <button className="modal-btn modal-cancel" onClick={() => setShowQuit(false)}>Keep playing</button>
              <button className="modal-btn modal-confirm" onClick={onBack}>Quit</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ONLINE LOBBY ─────────────────────────────────────────────────────────────
function OnlineLobby({ onStart, onBack }) {
  const [view, setView] = useState("menu");
  const [name, setName] = useState("");
  const [code, setCode] = useState("");
  const [joinCode, setJoinCode] = useState("");
  const [roomData, setRoomData] = useState(null);
  const [toast, setToast] = useState(null);
  const [cdNum, setCdNum] = useState(3);
  const pollRef = useRef(null);
  const t$ = m => { setToast(m); setTimeout(() => setToast(null), 2200); };

  const create = async () => {
    if (!name.trim()) { t$("Enter your name"); return; }
    const rc = generateCode();
    const room = { code:rc, host:name.trim(), guest:null, questions:getQs({n:10}), created:Date.now() };
    try {
      await window.storage?.set(`biq_room:${rc}`, JSON.stringify(room), true);
      setCode(rc); setRoomData(room); setView("waiting");
      // Clear any existing poll before starting a new one
      if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
      pollRef.current = setInterval(async () => {
        try {
          const res = await window.storage?.get(`biq_room:${rc}`, true);
          if (res) { let r = null; try { r = JSON.parse(res.value); } catch {} if (r) setRoomData(r); if (r.guest) { clearInterval(pollRef.current); setView("countdown"); } }
        } catch {}
      }, 2000);
    } catch { t$("Failed — try again"); }
  };

  const join = async () => {
    if (!name.trim()) { t$("Enter your name"); return; }
    if (!joinCode.trim()) { t$("Enter a room code"); return; }
    try {
      const res = await window.storage?.get(`biq_room:${joinCode.toUpperCase()}`, true);
      if (!res) { t$("Room not found"); return; }
      const r = JSON.parse(res.value);
      if (r.guest) { t$("Room is full"); return; }
      r.guest = name.trim();
      await window.storage?.set(`biq_room:${joinCode.toUpperCase()}`, JSON.stringify(r), true);
      setCode(joinCode.toUpperCase()); setRoomData(r); setView("countdown");
    } catch { t$("Room not found"); }
  };

  useEffect(() => {
    if (view !== "countdown") return;
    let c = 3; setCdNum(c);
    const t = setInterval(() => {
      c--;
      setCdNum(c);
      if (c <= 0) {
        clearInterval(t);
        // Defensive: roomData could be null if polling failed or user navigated
        if (!roomData || !roomData.questions) {
          t$("Connection lost — try again");
          setView("menu");
          return;
        }
        onStart({
          questions: roomData.questions,
          roomCode: code,
          playerName: name.trim(),
          isHost: roomData.host === name.trim()
        });
      }
    }, 1000);
    return () => clearInterval(t);
  }, [view, roomData, code, name, onStart]);

  useEffect(() => () => clearInterval(pollRef.current), []);

  if (view === "countdown") return <div className="cdown"><div className="cdown-n" key={cdNum}>{cdNum}</div><div className="cdown-s">Get ready</div></div>;

  if (view === "waiting") return (
    <div className="screen">
      <div className="page-hdr">
        <button className="back-btn" onClick={() => { clearInterval(pollRef.current); setView("menu"); }}>←</button>
        <div className="page-title">Room Created 🎉</div>
      </div>
      <div className="lcard">
        <div className="lcard-s" style={{marginBottom:16}}>Share this code with your friend — they enter it on their device to join.</div>
        <div className="code-box" style={{marginBottom:16}}>
          <div className="code-val" style={{letterSpacing:10,fontSize:36}}>{code}</div>
          <div className="code-hint">Tap to copy</div>
        </div>
        <div className="wait-row">
          {roomData?.guest
            ? <span style={{fontSize:15,color:"var(--green)",fontWeight:700}}>✓ {roomData.guest} joined! Starting…</span>
            : <div style={{display:"flex",alignItems:"center",gap:10}}>
                <div style={{display:"flex",gap:5}}>{[0,1,2].map(i=><div key={i} style={{width:8,height:8,borderRadius:"50%",background:"var(--accent)",animation:"wdot 1.2s ease "+(i*0.3)+"s infinite"}}/>)}</div>
                <span style={{fontSize:14,color:"var(--t2)"}}>Waiting for your friend to join…</span>
              </div>
          }
        </div>
      </div>
      <div style={{textAlign:"center",marginTop:12,fontSize:12,color:"var(--t3)",lineHeight:1.7}}>
        Make sure your friend has Ball IQ open on their device.<br/>Tap "Join with a code" and enter the code above.
      </div>
      {toast && <div className="toast">{toast}</div>}
    </div>
  );

  if (view === "create") return (
    <div className="screen">
      <div className="page-hdr"><button className="back-btn" onClick={() => setView("menu")}>←</button><div className="page-title">Create a Room</div></div>
      <div className="lcard">
        <div className="lcard-s">Set your name — a code will be generated for your friend.</div>
        <label className="inp-lbl">Your name</label>
        <input className="inp" placeholder="e.g. Marcus" value={name} onChange={e => setName(e.target.value)} />
        <button className="btn btn-p" onClick={create}>Create room →</button>
      </div>
      {toast && <div className="toast">{toast}</div>}
    </div>
  );

  if (view === "join") return (
    <div className="screen">
      <div className="page-hdr"><button className="back-btn" onClick={() => setView("menu")}>←</button><div className="page-title">Join a Room</div></div>
      <div className="lcard">
        <div className="lcard-s">Enter your name and the code your friend shared.</div>
        <label className="inp-lbl">Your name</label>
        <input className="inp" placeholder="e.g. Luka" value={name} onChange={e => setName(e.target.value)} />
        <label className="inp-lbl">Room code</label>
        <input className="inp" placeholder="XXXXX" value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())} maxLength={5} style={{fontFamily:"'JetBrains Mono',monospace",letterSpacing:5,fontSize:22,textAlign:"center"}} />
        <button className="btn btn-p" onClick={join}>Join →</button>
      </div>
      {toast && <div className="toast">{toast}</div>}
    </div>
  );

  return (
    <div className="screen">
      <div className="page-hdr"><button className="back-btn" onClick={onBack}>←</button><div className="page-title">Online 1v1</div></div>
      <p style={{fontSize:14,color:"var(--t2)",lineHeight:1.7,marginBottom:20}}>Create a room and share the code, or enter your friend's code. Works on any phone or browser.</p>
      <button className="btn btn-p" onClick={() => setView("create")}>Create a room</button>
      <div className="div-row"><div className="div-line"/><div className="div-lbl">or</div><div className="div-line"/></div>
      <button className="btn btn-s" onClick={() => setView("join")}>Join with a code</button>
    </div>
  );
}

// ─── LOCAL MULTIPLAYER SETUP ──────────────────────────────────────────────────
const EMOJIS = ["⚽","🏆","🔥","⚡","🎯","🥅","🧤","👑"];

// ─── SOCIAL HUB ───────────────────────────────────────────────────────────────
const SOCIAL_MODES = [
  { m:"classic", icon:"⏱️", label:"Standard Quiz",  desc:"10 questions, 20s each" },
  { m:"speed",   icon:"⚡", label:"Speed Round",    desc:"5 questions, 8s each" },
  { m:"survival",icon:"🔥", label:"Survival",       desc:"One wrong ends the game" },
  { m:"legends", icon:"📜", label:"Legends",        desc:"Classic football history" },
];

function SocialHub({ onOnline, onLocal, onBack }) {
  const [picked, setPicked] = useState("classic");
  return (
    <div className="screen">
      <div className="page-hdr">
        <button className="back-btn" onClick={onBack}>←</button>
        <div className="page-title">Challenge a Friend</div>
      </div>
      <div className="social-intro">Pick a game mode, then choose how to play:</div>
      <div className="mode-list" style={{marginBottom:20}}>
        {SOCIAL_MODES.map(({m,icon,label,desc}) => (
          <div key={m} className={`mode-item${picked===m?" mode-item-sel":""}`} onClick={() => setPicked(m)}>
            <div className="mi-icon">{icon}</div>
            <div className="mi-body"><div className="mi-name">{label}</div><div className="mi-desc">{desc}</div></div>
            {picked===m && <div style={{color:"var(--accent)",fontSize:18,fontWeight:700}}>✓</div>}
          </div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <button className="btn btn-p" onClick={() => onOnline(picked)} style={{background:"var(--accent)",color:"#0a1a00"}}>🌐 Online 1v1</button>
        <button className="btn" onClick={() => onLocal(picked)} style={{background:"var(--s2)",border:"1px solid var(--border2)",color:"var(--text)"}}>🤝 Local</button>
      </div>
      <div className="social-tip" style={{marginTop:12}}>Online: create a room code, friend joins on their device. Local: pass the phone between players.</div>
    </div>
  );
}

function LocalSetup({ onStart, onBack }) {
  const [players, setPlayers] = useState([{ name:"", id:0 }, { name:"", id:1 }]);
  const nextId = useRef(2);

  const addPlayer = () => {
    if (players.length >= 6) return;
    setPlayers(p => [...p, { name:"", id: nextId.current++ }]);
  };

  const removePlayer = (id) => {
    if (players.length <= 2) return;
    setPlayers(p => p.filter(pl => pl.id !== id));
  };

  const updateName = (id, val) => {
    setPlayers(p => p.map(pl => pl.id === id ? { ...pl, name: val } : pl));
  };

  const launch = () => {
    const named = players.map((pl, i) => ({
      ...pl,
      name: pl.name.trim() || `Player ${i + 1}`,
      emoji: EMOJIS[i % EMOJIS.length],
    }));
    onStart(named);
  };

  return (
    <div className="screen">
      <div className="page-hdr">
        <button className="back-btn" onClick={onBack}>←</button>
        <div className="page-title">Local Multiplayer</div>
      </div>

      <p style={{fontSize:14, color:"var(--t2)", lineHeight:1.7, marginBottom:22}}>
        Add up to 6 players. Everyone takes turns on the same device — perfect for halftime.
      </p>

      {players.map((pl, i) => (
        <div key={pl.id} className="player-input-row">
          <div className="player-num">{i + 1}</div>
          <input
            className="player-inp"
            placeholder={`Player ${i + 1}`}
            value={pl.name}
            onChange={e => updateName(pl.id, e.target.value)}
            maxLength={16}
          />
          {players.length > 2 && (
            <button className="remove-btn" onClick={() => removePlayer(pl.id)}>×</button>
          )}
        </div>
      ))}

      {players.length < 6 && (
        <button className="add-player-btn" onClick={addPlayer}>+ Add player</button>
      )}

      <button className="btn btn-p" onClick={launch}>
        Start with {players.length} players →
      </button>
    </div>
  );
}

// ─── LOCAL HANDOFF SCREEN ─────────────────────────────────────────────────────
function LocalHandoff({ player, previousScores, onReady }) {
  return (
    <div className="handoff">
      <div className="handoff-avatar">{player.emoji}</div>
      <div className="handoff-tag">Up next</div>
      <div className="handoff-name">{player.name}</div>
      <div className="handoff-sub">Pass the phone — it's your turn!</div>
      {previousScores.length > 0 && (
        <div className="handoff-scores">
          {previousScores.map((s, i) => (
            <div key={i} className="handoff-chip">{s.emoji} <strong>{s.name}</strong> {s.score}/10</div>
          ))}
        </div>
      )}
      <button className="btn btn-p" style={{width:"100%"}} onClick={onReady}>
        I'm ready →
      </button>
    </div>
  );
}

// ─── LOCAL RESULTS ────────────────────────────────────────────────────────────
function LocalResults({ scores, onHome, onRetry }) {
  const sorted = [...scores].sort((a, b) => b.score - a.score);
  const winner = sorted[0];
  const tied = sorted.filter(s => s.score === winner.score).length > 1;

  return (
    <div className="screen" style={{paddingTop:8}}>
      <div className="rc" style={{marginBottom:16}}>
        <div className="rc-icon">{winner.emoji}</div>
        <div className="rc-title">{tied ? "It's a draw!" : `${winner.name} wins!`}</div>
        {!tied && <div className="rc-sub" style={{marginTop:4}}>{winner.score}/10 correct</div>}
      </div>

      <div className="podium">
        {sorted.map((s, i) => (
          <div key={s.id} className={`podium-row${i === 0 && !tied ? " gold" : ""}`}>
            <div className="pod-rank">{i === 0 && !tied ? "🏆" : i === 1 ? "🥈" : i === 2 ? "🥉" : `${i+1}`}</div>
            <div className="pod-name">{s.emoji} {s.name}</div>
            <div className="pod-score">{s.score}/10</div>
          </div>
        ))}
      </div>

      {xpEarned > 0 && <div className="xp-earned-badge">+{xpEarned} XP earned</div>}
      {wrongAnswers && wrongAnswers.length > 0 && (
        <div className="wrong-review">
          <div className="wr-title">📖 Review — {wrongAnswers.length} missed</div>
          {wrongAnswers.map((w, i) => (
            <div key={i} className="wr-item">
              <div className="wr-q">{w.q}</div>
              <div className="wr-a"><span className="wr-tick">✓</span>{w.correct}</div>
            </div>
          ))}
        </div>
      )}
      <button className="btn btn-share" onClick={onShare}>Share Score 📤</button>
      <button className="btn btn-p" onClick={onRetry}>Play Again</button>
      <button className="btn btn-s" onClick={onHome}>Back to Home</button>
    </div>
  );
}


// ─── XP + LEVEL SYSTEM ────────────────────────────────────────────────────────
const LEVELS = [
  { name:"Sunday League",  xpNeeded:0,    icon:"⚽" },
  { name:"Non-League",     xpNeeded:100,  icon:"🌱" },
  { name:"Championship",   xpNeeded:300,  icon:"📈" },
  { name:"Premier League", xpNeeded:700,  icon:"🏟️" },
  { name:"Champions League",xpNeeded:1500, icon:"⭐" },
  { name:"Legend",         xpNeeded:3000, icon:"🐐" },
];

function getLevelInfo(xp) {
  let level = LEVELS[0];
  let nextLevel = LEVELS[1];
  for (let i = LEVELS.length - 1; i >= 0; i--) {
    if (xp >= LEVELS[i].xpNeeded) {
      level = LEVELS[i];
      nextLevel = LEVELS[i + 1] || null;
      break;
    }
  }
  const progress = nextLevel
    ? Math.round(((xp - level.xpNeeded) / (nextLevel.xpNeeded - level.xpNeeded)) * 100)
    : 100;
  return { level, nextLevel, progress };
}

function getXPForResult(score, total, mode) {
  if (mode === "hotstreak") {
    // Hot Streak: 5 XP per correct, bonus tiers
    const tierBonus = score >= 25 ? 100 : score >= 15 ? 50 : score >= 8 ? 20 : 0;
    return score * 5 + tierBonus;
  }
  if (mode === "truefalse") {
    // True/False: 6 XP per correct, perfect bonus
    const perfectBonus = score === total ? 40 : 0;
    return score * 6 + perfectBonus;
  }
  if (mode === "wc2026") {
    // WC2026: same as classic but with World Cup bonus
    const pct = score / total;
    const perfectBonus = score === total ? 60 : 0;
    return Math.round(score * 10 + pct * 20) + perfectBonus;
  }
  const base = score * 10;
  const bonus = mode === "survival" ? Math.floor(score * 1.5) * 10 : 0;
  const perfectBonus = score === total && mode !== "survival" ? 50 : 0;
  return base + bonus + perfectBonus;
}


// ─── CANVAS SHARE CARD ────────────────────────────────────────────────────────
function drawShareCard({ name, avatar, levelName, levelIcon, xp, iq, pctile, streak, gamesPlayed, theme }) {
  const canvas = document.createElement("canvas");
  canvas.width = 600; canvas.height = 320;
  const ctx = canvas.getContext("2d");
  const dark = theme !== "light";

  // Background
  ctx.fillStyle = dark ? "#0C0E13" : "#F2F2F7";
  ctx.roundRect(0, 0, 600, 320, 20);
  ctx.fill();

  // Accent bar top
  const grad = ctx.createLinearGradient(0, 0, 600, 0);
  grad.addColorStop(0, "#4ADE80");
  grad.addColorStop(1, "#3B82F6");
  ctx.fillStyle = grad;
  ctx.roundRect(0, 0, 600, 6, [20, 20, 0, 0]);
  ctx.fill();

  // Card surface
  ctx.fillStyle = dark ? "#161921" : "#FFFFFF";
  ctx.shadowColor = dark ? "rgba(0,0,0,0.4)" : "rgba(0,0,0,0.1)";
  ctx.shadowBlur = 20;
  ctx.roundRect(24, 24, 552, 272, 16);
  ctx.fill();
  ctx.shadowBlur = 0;

  // Avatar circle
  ctx.fillStyle = "rgba(88,204,2,0.12)";
  ctx.beginPath(); ctx.arc(80, 100, 36, 0, Math.PI*2); ctx.fill();
  ctx.font = "38px serif";
  ctx.textAlign = "center";
  ctx.fillText(avatar || "⚽", 80, 113);

  // Name + level
  ctx.textAlign = "left";
  ctx.fillStyle = dark ? "#F0F1F5" : "#000000";
  ctx.font = "bold 22px Inter, sans-serif";
  ctx.fillText(name || "Ball IQ Player", 130, 88);
  ctx.fillStyle = dark ? "#9BA0B8" : "#6B7280";
  ctx.font = "14px Inter, sans-serif";
  ctx.fillText(levelIcon + " " + levelName + "  ·  " + xp.toLocaleString() + " XP", 130, 112);

  // Ball IQ score — big number
  if (iq) {
    ctx.fillStyle = "#4ADE80";
    ctx.font = "bold 56px Inter, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText(String(iq), 96, 210);
    ctx.fillStyle = dark ? "#9BA0B8" : "#6B7280";
    ctx.font = "11px Inter, sans-serif";
    ctx.fillText("BALL IQ", 96, 228);
    ctx.font = "11px Inter, sans-serif";
    ctx.fillText("TOP " + pctile + "%", 96, 244);
  }

  // Stats row
  const stats = [
    { val: String(gamesPlayed), key: "GAMES" },
    { val: "🔥" + streak, key: "STREAK" },
  ];
  stats.forEach((s, i) => {
    const x = iq ? 200 + i * 130 : 130 + i * 150;
    ctx.fillStyle = dark ? "#F0F1F5" : "#000";
    ctx.font = "bold 28px Inter, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText(s.val, x, 200);
    ctx.fillStyle = dark ? "#9BA0B8" : "#6B7280";
    ctx.font = "11px Inter, sans-serif";
    ctx.fillText(s.key, x, 220);
  });

  // Brand watermark
  ctx.fillStyle = dark ? "#9BA0B8" : "#6B7280";
  ctx.font = "12px Inter, sans-serif";
  ctx.textAlign = "right";
  ctx.fillText("Ball IQ ⚽", 572, 280);

  return canvas.toDataURL("image/png");
}

async function shareCard(dataURL, fallbackText) {
  try {
    const blob = await (await fetch(dataURL)).blob();
    const file = new File([blob], "balliq-score.png", { type: "image/png" });
    if (navigator.share && navigator.canShare?.({ files: [file] })) {
      await navigator.share({ files: [file] });
      return;
    }
  } catch {}
  // Fallback: open image in new tab or copy text
  try {
    const a = document.createElement("a");
    a.href = dataURL; a.download = "balliq-score.png"; a.click();
  } catch {
    navigator.clipboard?.writeText(fallbackText).catch(() => {});
  }
}


// ─── CONFETTI ─────────────────────────────────────────────────────────────────
function Confetti() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const pieces = Array.from({length:80}, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height - canvas.height,
      w: Math.random() * 10 + 5,
      h: Math.random() * 6 + 3,
      r: Math.random() * Math.PI * 2,
      dr: (Math.random() - 0.5) * 0.2,
      vy: Math.random() * 3 + 2,
      vx: (Math.random() - 0.5) * 2,
      color: ["#58CC02","#FFC800","#FF4B4B","#1CB0F6","#CE82FF","#FF9600"][Math.floor(Math.random()*6)],
    }));
    let alive = true;
    const draw = () => {
      if (!alive) return;
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      pieces.forEach(p => {
        p.y += p.vy; p.x += p.vx; p.r += p.dr;
        ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.r);
        ctx.fillStyle = p.color; ctx.globalAlpha = Math.max(0, 1 - p.y / canvas.height);
        ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h);
        ctx.restore();
      });
      if (pieces.some(p => p.y < canvas.height)) requestAnimationFrame(draw);
    };
    requestAnimationFrame(draw);
    return () => { alive = false; };
  }, []);
  return <canvas ref={canvasRef} style={{position:"fixed",top:0,left:0,pointerEvents:"none",zIndex:500,width:"100%",height:"100%"}} />;
}


// ─── HARD RIGHT BURST ────────────────────────────────────────────────────────
// Lightweight, quick particle burst used when a user gets a HARD question right.
// Different from full Confetti — faster, more focused, emanates from center-bottom.
function HardRightBurst({ onComplete }) {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    // Origin: center of screen, slightly above middle (where the answer would be)
    const ox = canvas.width / 2;
    const oy = canvas.height * 0.55;
    // 40 particles burst outward and upward
    const pieces = Array.from({length: 40}, (_, i) => {
      const angle = (i / 40) * Math.PI * 2 + (Math.random() - 0.5) * 0.3;
      const speed = 6 + Math.random() * 6;
      return {
        x: ox,
        y: oy,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed - 3,  // bias upward
        w: Math.random() * 8 + 4,
        h: Math.random() * 4 + 2,
        r: Math.random() * Math.PI * 2,
        dr: (Math.random() - 0.5) * 0.3,
        life: 1,
        color: ["#58CC02", "#FFC800", "#FBBF24", "#3BA80E"][Math.floor(Math.random() * 4)],
      };
    });
    let alive = true;
    let frame = 0;
    const draw = () => {
      if (!alive) return;
      frame++;
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      let anyAlive = false;
      pieces.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.vy += 0.25;  // gravity
        p.vx *= 0.99;  // air resistance
        p.r += p.dr;
        p.life -= 0.015;
        if (p.life > 0) {
          anyAlive = true;
          ctx.save();
          ctx.translate(p.x, p.y);
          ctx.rotate(p.r);
          ctx.fillStyle = p.color;
          ctx.globalAlpha = Math.max(0, p.life);
          ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h);
          ctx.restore();
        }
      });
      if (anyAlive && frame < 90) requestAnimationFrame(draw);
      else { alive = false; if (onComplete) onComplete(); }
    };
    requestAnimationFrame(draw);
    return () => { alive = false; };
  }, [onComplete]);
  return <canvas ref={canvasRef} style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:500}} />;
}


// ─── BALL IQ RESULTS ─────────────────────────────────────────────────────────
// Extracted into its own component so hooks are never called conditionally
function BallIQResults({ result, iqHistory, onRetry, onShare, onHome }) {
  const iq = calcBallIQ(result.score, result.total);
  const pctile = iqPercentile(iq);
  const label = iqLabel(iq);
  const ringPct = Math.min((iq - 60) / 85, 1);
  const showIQConfetti = iq >= 120;

  const [displayIQ, setDisplayIQ] = useState(60);
  const [ringDisplay, setRingDisplay] = useState(0);
  const [revealed, setRevealed] = useState(false);

  useEffect(() => {
    const delay = setTimeout(() => {
      setRevealed(true);
      const start = 60;
      const duration = 1400;
      const startTime = Date.now();
      const tick = () => {
        const elapsed = Date.now() - startTime;
        const progress = Math.min(elapsed / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        setDisplayIQ(Math.round(start + (iq - start) * eased));
        setRingDisplay(ringPct * eased);
        if (progress < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    }, 400);
    return () => clearTimeout(delay);
  }, []);

  return (
    <div className="screen" style={{paddingTop:8}}>
      {showIQConfetti && revealed && <Confetti />}
      <div className={`iq-result${revealed ? " iq-revealed" : ""}`}>
        <div style={{fontSize:13,color:"var(--t2)",fontWeight:600,marginBottom:4}}>Your Ball IQ</div>
        <div className="iq-label" style={{opacity: revealed ? 1 : 0, transition:"opacity 0.5s 0.3s"}}>{label}</div>
        <div className="iq-score-wrap">
          <div className={`iq-ring${iq >= 120 ? " great" : ""}`} style={{background:`conic-gradient(var(--accent) ${ringDisplay*360}deg, var(--s3) 0deg)`}}>
            <div className="iq-ring-inner">
              <div className="iq-num">{displayIQ}</div>
              <div className="iq-sub">Ball IQ</div>
            </div>
          </div>
        </div>
        <div className="iq-pct" style={{opacity: revealed ? 1 : 0, transition:"opacity 0.5s 1.6s", lineHeight:1.8}}>
          Better than <strong>{pctile}%</strong> of football fans
          {pctile >= 90 && <div style={{fontSize:12,color:"var(--gold)",fontWeight:700,marginTop:4}}>🏆 Elite level knowledge!</div>}
          {pctile >= 75 && pctile < 90 && <div style={{fontSize:12,color:"var(--accent)",fontWeight:600,marginTop:4}}>⚡ Sharp — you really know your football</div>}
          {pctile >= 50 && pctile < 75 && <div style={{fontSize:12,color:"var(--t2)",marginTop:4}}>Keep playing to climb higher!</div>}
          {pctile < 50 && <div style={{fontSize:12,color:"var(--t2)",marginTop:4}}>Retake the test to boost your score</div>}
        </div>
      </div>
      <div className="s-row">
        <div className="sbox"><div className="sbox-v" style={{color:"var(--green)"}}>{result.score}</div><div className="sbox-k">Correct</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--red)"}}>{result.total - result.score}</div><div className="sbox-k">Wrong</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--gold)"}}>{result.bestStreak||0}</div><div className="sbox-k">Streak</div></div>
      </div>
      {iqHistory && iqHistory.length > 1 && (
        <div className="iq-history">
          <div className="iq-hist-label">Your last {iqHistory.length} scores</div>
          <div className="iq-hist-bars">
            {iqHistory.map((h, i) => (
              <div key={i} className="iq-hist-col">
                <div className="iq-hist-bar" style={{height:`${Math.round(((h.iq-60)/85)*44)+4}px`, background: h.iq >= 120 ? "var(--accent)" : h.iq >= 100 ? "var(--gold)" : "var(--t3)"}}/>
                <div className="iq-hist-n">{h.iq}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      <button className="btn btn-p" onClick={onRetry} style={{marginBottom:8}}>Retake Test</button>
      <button className="btn btn-share" onClick={onShare}>Share Score 📤</button>
      <button className="btn btn-s" onClick={onHome}>Back to Home</button>
    </div>
  );
}


// ─── DAILY SOCIAL PROOF ───────────────────────────────────────────────────────
// Shows "You beat X% of players today" based on mock score distribution.
// Uses seeded randomness so the number doesn't change between views.
// Distribution follows a realistic curve: most players score 5-7, few score 10.
function DailySocialProof({ score, total }) {
  const { percentile, playersToday } = useMemo(() => {
    // Realistic score distribution for 10-question daily:
    // Score 0-2: 8%, 3-4: 22%, 5-6: 35%, 7-8: 25%, 9: 8%, 10: 2%
    const cumulativeBelow = [0, 2, 5, 14, 30, 50, 65, 80, 92, 98, 100];
    // Percentile = % of players you beat (strictly less than your score)
    const pct = cumulativeBelow[Math.max(0, Math.min(10, score))];
    
    // Seed the "players today" number from the day
    const now = new Date();
    const daySeed = now.getFullYear() * 10000 + (now.getMonth()+1) * 100 + now.getDate();
    // Pseudo-random range 12,000 - 28,000
    const base = 12000 + ((daySeed * 9301 + 49297) % 16000);
    // Add some "hour-based" growth to feel alive
    const hourMultiplier = 0.3 + (now.getHours() / 24) * 0.7;
    const players = Math.round(base * hourMultiplier);
    
    return { percentile: pct, playersToday: players };
  }, [score, total]);
  
  // Animated count-up for percentile
  const [displayPct, setDisplayPct] = useState(0);
  useEffect(() => {
    let frame = 0;
    const duration = 1200;
    const start = performance.now();
    const animate = (t) => {
      const elapsed = t - start;
      const progress = Math.min(1, elapsed / duration);
      // Ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplayPct(Math.round(percentile * eased));
      if (progress < 1) frame = requestAnimationFrame(animate);
    };
    frame = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame);
  }, [percentile]);
  
  // Emoji + message based on percentile
  const { emoji, message } = (() => {
    if (percentile >= 95) return { emoji: "🐐", message: "Elite performance — top 5% today" };
    if (percentile >= 80) return { emoji: "🏆", message: "World class — top 20%" };
    if (percentile >= 60) return { emoji: "⚽", message: "Strong showing — above average" };
    if (percentile >= 40) return { emoji: "📈", message: "Right around average today" };
    if (percentile >= 20) return { emoji: "📚", message: "Tough day — keep playing to climb" };
    return { emoji: "💪", message: "Everyone starts somewhere" };
  })();
  
  return (
    <div style={{
      background: "var(--s1)",
      border: "1px solid var(--border)",
      borderRadius: 16,
      padding: "20px 22px",
      marginBottom: 12,
      position: "relative",
      overflow: "hidden",
    }}>
      <div style={{position:"absolute",top:0,left:0,right:0,height:2,background:"linear-gradient(90deg,transparent 0%,var(--accent) 50%,transparent 100%)",opacity:0.8}} />
      {/* Subtle header */}
      <div style={{
        fontSize: 10,
        fontWeight: 800,
        color: "var(--accent)",
        letterSpacing: 1.5,
        textTransform: "uppercase",
        fontFamily: "'JetBrains Mono', monospace",
        marginBottom: 10,
        display: "flex",
        alignItems: "center",
        gap: 6,
      }}>
        <span style={{ color: "#dc2626", fontSize: 10, animation: "dheroPulse 2s ease-in-out infinite" }}>●</span>
        DAILY CHALLENGE · LIVE
      </div>
      
      {/* Big percentile number */}
      <div style={{ display: "flex", alignItems: "baseline", gap: 12, marginBottom: 6 }}>
        <div style={{
          fontSize: 48,
          fontWeight: 900,
          letterSpacing: -2,
          color: "var(--t1)",
          lineHeight: 1,
          fontFamily: "'JetBrains Mono', monospace",
        }}>
          {displayPct}<span style={{ fontSize: 28, color: "var(--accent)" }}>%</span>
        </div>
        <div style={{ fontSize: 32, lineHeight: 1 }}>{emoji}</div>
      </div>
      
      <div style={{
        fontSize: 14,
        fontWeight: 700,
        color: "var(--t1)",
        marginBottom: 4,
      }}>
        You beat <span style={{ color: "var(--accent)" }}>{percentile}%</span> of players today
      </div>
      
      <div style={{
        fontSize: 12,
        color: "var(--t2)",
        marginBottom: 10,
      }}>
        {message}
      </div>
      
      {/* Progress bar showing percentile */}
      <div style={{
        height: 6,
        background: "var(--s2)",
        borderRadius: 3,
        overflow: "hidden",
        marginBottom: 10,
      }}>
        <div style={{
          height: "100%",
          width: `${displayPct}%`,
          background: "linear-gradient(90deg, #58cc02 0%, #3ba80e 100%)",
          borderRadius: 3,
          transition: "width 0.1s linear",
        }} />
      </div>
      
      {/* Players count footer */}
      <div style={{
        fontSize: 11,
        color: "var(--t3)",
        display: "flex",
        alignItems: "center",
        gap: 5,
        fontFamily: "'JetBrains Mono', monospace",
      }}>
        <span>👥</span>
        <span>{playersToday.toLocaleString()} played today</span>
      </div>
    </div>
  );
}

function Results({ result, mode, onHome, onRetry, onShare, iqHistory, survivalBest, wrongAnswers }) {
  const isPerfect = result && result.score === result.total && result.total >= 10;
  const pct = Math.round((result.score / result.total) * 100);
  useEffect(() => { if (isPerfect) haptic("levelup"); }, [isPerfect]);
  const isSurvival = mode === "survival";
  const emoji = isSurvival
    ? (result.score >= 20 ? "🏆" : result.score >= 10 ? "🔥" : result.score >= 5 ? "⚽" : "💀")
    : (pct === 100 ? "🐐" : pct >= 80 ? "🏆" : pct >= 60 ? "⚽" : pct >= 40 ? "🎯" : pct === 0 ? "😬" : "📚");
  const title = isSurvival
    ? (result.score >= 20 ? "Unstoppable!" : result.score >= 10 ? "On Fire!" : result.score >= 5 ? "Good Effort" : "Better luck next time!")
    : (pct === 100 ? "Perfect Score! 🐐" : result.score === 9 && result.total === 10 ? "So close to perfect! 🎯" : pct >= 80 ? "World Class" : pct >= 60 ? "Solid Result" : pct >= 40 ? "Not Bad" : pct === 0 ? "Even Mourinho had bad days…" : "Keep Watching");

  if (mode === "balliq") {
    return <BallIQResults result={result} iqHistory={iqHistory} onRetry={onRetry} onShare={onShare} onHome={onHome} />;
  }

  const xpEarned = getXPForResult(result.score, result.total, mode);
  const isSpeed = mode === 'speed';
  const isDaily = mode === "daily";
  const showConfetti = isSurvival ? result.score >= 10 : (mode === "balliq" ? false : pct >= 80);
  return (
    <div className="screen" style={{paddingTop:8}}>
      {isPerfect && <Confetti />}
      {showConfetti && <Confetti />}
      
      {/* ── DAILY SOCIAL PROOF — shown only for Daily Challenge ── */}
      {isDaily && <DailySocialProof score={result.score} total={result.total} />}
      
      <div className="rc">
        <div className="rc-icon">{emoji}</div>
        <div className="rc-title">{title}</div>
        {isSpeed
          ? <><div className="score-big" style={{color:"var(--gold)"}}>{(result.speedScore||0).toLocaleString()}</div><div className="score-pct">{result.score}/{result.total} correct · speed bonus included</div></>
          : isSurvival
          ? <><div className="score-big">{result.score}<span style={{fontSize:22,color:"var(--t2)",fontWeight:500}}> correct</span></div><div className="score-pct">in a row before missing one</div></>
          : <><div className="score-big">{result.score}<span style={{fontSize:30,color:"var(--t2)"}}>/{result.total}</span></div><div className="score-pct">{pct}% correct</div></>
        }
      </div>
      <div className="s-row">
        <div className="sbox"><div className="sbox-v" style={{color:"var(--green)"}}>{result.score}</div><div className="sbox-k">Correct</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--red)"}}>{isSurvival ? 1 : result.total - result.score}</div><div className="sbox-k">Wrong</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--gold)"}}>{result.bestStreak||0}</div><div className="sbox-k">🔥 Streak</div></div>
      </div>
      {result.winner && <div style={{textAlign:"center",marginBottom:14,fontSize:15,fontWeight:700,color:"var(--gold)"}}>🏆 {result.winner} wins!</div>}

      {/* Primary actions FIRST — always visible without scrolling */}
      {xpEarned > 0 && <div className="xp-earned-badge">+{xpEarned} XP earned ⚡</div>}
      <button className="btn btn-p" onClick={onRetry} style={{marginBottom:8,fontSize:17,fontWeight:800,letterSpacing:0.3}}>▶ Play Again</button>
      <button className="btn btn-share" onClick={onShare} style={{marginBottom:8}}>Share Score 📤</button>
      <button className="btn btn-s" onClick={onHome}>Back to Home</button>

      {/* Wrong answers review — below the fold, players scroll if interested */}
      {wrongAnswers && wrongAnswers.length > 0 && (
        <div style={{marginTop:8}}>
          <div style={{fontSize:12,fontWeight:700,color:"var(--t2)",letterSpacing:1,textTransform:"uppercase",marginBottom:8,textAlign:"center"}}>
            📚 Review {wrongAnswers.length} Missed {wrongAnswers.length === 1 ? "Answer" : "Answers"}
          </div>
          <div className="wrong-review">
            {wrongAnswers.map((w, i) => (
              <div key={i} className="wr-item">
                <div className="wr-q">{w.q}</div>
                <div className="wr-a"><span className="wr-tick">✓</span>{w.correct}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}


// ─── HOT STREAK RESULTS ───────────────────────────────────────────────────────
function HotStreakResults({ result, onRetry, onHome, onShare, prevBest }) {
  const score = result.score;
  const answered = result.total;
  const isNewBest = prevBest === 0 || score > prevBest;
  const pct = answered > 0 ? Math.round((score / answered) * 100) : 0;
  const emoji = score >= 25 ? "🐐" : score >= 15 ? "🔥" : score >= 8 ? "⚡" : "⏱️";
  const title = score >= 25 ? "Unstoppable!" : score >= 15 ? "On Fire!" : score >= 8 ? "Sharp!" : "Keep Practising!";
  const xpEarned = score * 8;
  return (
    <div className="screen" style={{paddingTop:8}}>
      {score >= 15 && <Confetti />}
      <div style={{textAlign:"center",padding:"8px 0 4px"}}>
        <span style={{fontSize:10,fontFamily:"'JetBrains Mono',monospace",color:"var(--accent)",letterSpacing:2,textTransform:"uppercase"}}>⚡🔥 HOT STREAK</span>
      </div>
      <div className="rc">
        <div className="rc-icon">{emoji}</div>
        <div className="rc-title">{title}</div>
        <div className="score-big" style={{color:"var(--accent)"}}>{score}<span style={{fontSize:22,color:"var(--t2)",fontWeight:500}}> correct</span></div>
        <div className="score-pct">in 60 seconds · {answered} answered · {pct}% accuracy</div>
        {isNewBest && prevBest > 0 && <div style={{marginTop:8,fontSize:13,fontWeight:700,color:"var(--gold)"}}>🏆 New Personal Best! (was {prevBest})</div>}
        {prevBest > 0 && !isNewBest && <div style={{marginTop:8,fontSize:13,color:"var(--t2)"}}>Personal best: {prevBest}</div>}
      </div>
      <div className="s-row">
        <div className="sbox"><div className="sbox-v" style={{color:"var(--accent)"}}>{score}</div><div className="sbox-k">Correct</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--t2)"}}>{answered}</div><div className="sbox-k">Answered</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--gold)"}}>{pct}%</div><div className="sbox-k">Accuracy</div></div>
      </div>
      {xpEarned > 0 && <div className="xp-earned-badge">+{xpEarned} XP earned ⚡</div>}
      <button className="btn btn-p" onClick={onRetry} style={{marginBottom:8}}>▶ Play Again</button>
      <button className="btn btn-share" onClick={() => {
        const msg = `⚡🔥 ${score} correct in 60 seconds on Ball IQ Hot Streak!\nThink you can beat that?\n#BallIQ`;
        if (navigator.share) navigator.share({title:"Ball IQ",text:msg}).catch(()=>{});
        else navigator.clipboard?.writeText(msg).then(()=>alert("Copied to clipboard!")).catch(()=>{});
      }} style={{marginBottom:8}}>Share Score 📤</button>
      <button className="btn btn-s" onClick={onHome}>Back to Home</button>
    </div>
  );
}

// ─── TRUE OR FALSE RESULTS ────────────────────────────────────────────────────
function TrueFalseResults({ result, onRetry, onHome, onShare }) {
  const { score, total } = result;
  const pct = Math.round((score / total) * 100);
  const emoji = pct === 100 ? "🧠" : pct >= 80 ? "✅" : pct >= 60 ? "⚽" : pct >= 40 ? "🤔" : "❌";
  const title = pct === 100 ? "Perfect — You Know Your Football!" : pct >= 80 ? "Sharp!" : pct >= 60 ? "Solid!" : pct >= 40 ? "Room to Improve" : "Back to School!";
  const xpEarned = score * 8;
  return (
    <div className="screen" style={{paddingTop:8}}>
      {pct >= 80 && <Confetti />}
      <div style={{textAlign:"center",padding:"8px 0 4px"}}>
        <span style={{fontSize:10,fontFamily:"'JetBrains Mono',monospace",color:"var(--accent)",letterSpacing:2,textTransform:"uppercase"}}>✅ TRUE OR FALSE</span>
      </div>
      <div className="rc">
        <div className="rc-icon">{emoji}</div>
        <div className="rc-title">{title}</div>
        <div className="score-big">{score}<span style={{fontSize:30,color:"var(--t2)"}}>/{total}</span></div>
        <div className="score-pct">{pct}% correct</div>
      </div>
      <div className="s-row">
        <div className="sbox"><div className="sbox-v" style={{color:"var(--green)"}}>{score}</div><div className="sbox-k">Correct</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--red)"}}>{total - score}</div><div className="sbox-k">Wrong</div></div>
        <div className="sbox"><div className="sbox-v" style={{color:"var(--gold)"}}>{pct}%</div><div className="sbox-k">Accuracy</div></div>
      </div>
      {xpEarned > 0 && <div className="xp-earned-badge">+{xpEarned} XP earned ⚡</div>}
      <button className="btn btn-p" onClick={onRetry} style={{marginBottom:8}}>▶ Play Again</button>
      <button className="btn btn-share" onClick={() => {
        const msg = `✅ ${score}/${total} on Ball IQ True or False!\n${Math.round(score/total*100)}% accuracy — can you do better?\n#BallIQ`;
        if (navigator.share) navigator.share({title:"Ball IQ",text:msg}).catch(()=>{});
        else navigator.clipboard?.writeText(msg).then(()=>alert("Copied to clipboard!")).catch(()=>{});
      }} style={{marginBottom:8}}>Share Score 📤</button>
      <button className="btn btn-s" onClick={onHome}>Back to Home</button>
    </div>
  );
}


